#include <iostream>
#include <algorithm>

using namespace std;

struct TreeNode
{
    int data;
    TreeNode *left;
    TreeNode *right;
};

int height(TreeNode *node)
{
    if (node == nullptr) // BASE CASE — an empty tree has height -1 (no edges at all)
    {
        return -1;
    }
    return 1 + max(height(node->left), height(node->right)); // RECURSIVE CASE
}

int main()
{
    TreeNode *root = new TreeNode{1, nullptr, nullptr};
    root->left = new TreeNode{2, nullptr, nullptr};
    root->right = new TreeNode{3, nullptr, nullptr};
    root->left->left = new TreeNode{4, nullptr, nullptr};

    cout << height(root) << endl;

    return 0;
}

